select count(*) from postgres.comments as c, postgres.postlinks as pl, postgres.posthistory as ph, postgres.votes as v, postgres.posts as p where pl.postid = p.id and c.postid = p.id and v.postid = p.id and ph.postid = p.id and c.score=0 and pl.creationdate>=timestamp '2011-11-21 22:39:41' and pl.creationdate<=timestamp '2014-09-01 16:29:56' and v.creationdate>=timestamp '2010-07-22 00:00:00' and v.creationdate<=timestamp '2014-09-14 00:00:00';
